+        var raw = text.Split(s_sentenceDelimiters, StringSplitOptions.RemoveEmptyEntries);
+        var sentences = new List<string>();
+
+        foreach (var s in raw)
+        {
+            var trimmed = s.Trim();
+            if (trimmed.Length > 0)
+            {
+                sentences.Add(trimmed);
+            }
+        }
+
+        return sentences;
+    }
+
+    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in WordPattern().Matches(sentence).Select(m => m.Value))
+            {
+                if (word.Length <= 2) continue; // skip very short / stop-ish words
+                freq[word] = freq.GetValueOrDefault(word) + 1;
+            }
+        }
+
+        return freq;
+    }
+
+    private static List<(int Index, double Score)> ScoreSentences(
+        List<string> sentences,
+        Dictionary<string, int> wordFrequencies)
+    {
+        var scored = new List<(int Index, double Score)>();
+
+        for (var i = 0; i < sentences.Count; i++)
+        {
+            var words = WordPattern().Matches(sentences[i]).Select(m => m.Value).ToList();
+            if (words.Count == 0)
+            {
+                scored.Add((i, 0));
+                continue;
+            }
+
+            double score = words
+                .Where(w => w.Length > 2)
+                .Sum(w => wordFrequencies.GetValueOrDefault(w));
+
+            // Normalize by sentence length to avoid bias toward long sentences.
+            scored.Add((i, score / words.Count));
+        }
+
+        return scored;
+    }
